import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"防诈骗提示","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/anti-fraud.md","filePath":"zh-CN/account/anti-fraud.md"}'),n={name:"account/anti-fraud.md"};function i(l,a,s,d,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="防诈骗提示" tabindex="-1">防诈骗提示 <a class="header-anchor" href="#防诈骗提示" aria-label="Permalink to &quot;防诈骗提示&quot;">​</a></h1><p>钓鱼诈骗防范、官方联系方式、双重认证机制及四招防骗建议。</p><h2 id="警惕钓鱼诈骗" tabindex="-1">警惕钓鱼诈骗 <a class="header-anchor" href="#警惕钓鱼诈骗" aria-label="Permalink to &quot;警惕钓鱼诈骗&quot;">​</a></h2><p>近期市场上出现冒充金融机构名义发送短信、WhatsApp 信息或钓鱼链接的诈骗行为。长桥证券（香港）官方发出的 WhatsApp 信息及手机短信目前均不包含任何外部链接。</p><p>如收到任何自称来自长桥证券但附有可疑链接的信息，请勿点击、勿转发、勿回复，建议第一时间与官方客服核实。</p><h2 id="长桥官方联系方式" tabindex="-1">长桥官方联系方式 <a class="header-anchor" href="#长桥官方联系方式" aria-label="Permalink to &quot;长桥官方联系方式&quot;">​</a></h2><p>统一外呼号码：+852 3851 1777、+852 3851 1788<br> WhatsApp：+852 5223 6373、+852 5170 2190、+852 6452 3546、+852 5161 0057<br> 官方电邮：service@longbridge.hk<br> 长桥 App 内线上客服</p><h2 id="双重验证" tabindex="-1">双重验证 <a class="header-anchor" href="#双重验证" aria-label="Permalink to &quot;双重验证&quot;">​</a></h2><p>长桥证券（香港）已全面启用双重认证（2FA）机制，从登录、交易到账户操作，全方位保护身份资讯与资金安全。</p><h2 id="防骗四招" tabindex="-1">防骗四招 <a class="header-anchor" href="#防骗四招" aria-label="Permalink to &quot;防骗四招&quot;">​</a></h2><ol><li><strong>认清官方信息来源</strong>：仅通过长桥证券 App、官网及认证社交平台发布资讯</li><li><strong>不轻信陌生信息</strong>：收到自称「长桥客服」的陌生来电或信息，请提高警觉</li><li><strong>不提供个人资料</strong>：长桥不会通过电话、电邮或信息主动索取登录资料、验证码或密码</li><li><strong>定期检查账户安全</strong>：建议定期检视账户安全纪录，并养成更换密码的习惯</li></ol>',11)])])}const _=t(n,[["render",i]]);export{u as __pageData,_ as default};
